function fn_get_cookie__string(name) {
    const match = document.cookie.match(new RegExp("(?:^|; )" + name + "=([^;]*)"));
    const val = match ? match[1] : "";
    console.log("[zero] get_cookie(" + name + ") = " + JSON.stringify(val) + " (all cookies: " + document.cookie + ")");
    return val;
}

